my $SESSION_TIMEOUT = 3600;  # 1 hour in seconds
my $COOKIE_NAME     = 'SESSION_ID';

# --- Session Manager Package ---
package SessionManager;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir     => $opts{session_dir}     || $SESSION_DIR,
        session_prefix  => $opts{session_prefix}  || $SESSION_PREFIX,
        session_timeout => $opts{session_timeout} || $SESSION_TIMEOUT,
        cookie_name     => $opts{cookie_name}     || $COOKIE_NAME,
        session_id      => undef,
        data            => {},
        is_new          => 0,
        cgi             => $opts{cgi} || CGI->new(),
    }, $class;

    return $self;
}

# Generate a cryptographically reasonable session ID
sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('', map { chr(int(rand(256))) } 1..32);
    my $session_id = sha256_hex($random_data . time() . $$ . rand());
    return $session_id;
}

# Validate session ID format to prevent directory traversal and injection
sub _validate_session_id {
    my ($self, $session_id) = @_;
    return 0 unless defined $session_id;
    # Only allow hex characters (from sha256_hex)
    return ($session_id =~ /^[a-f0-9]{64}$/) ? 1 : 0;
}

# Get the full file path for a session
sub _session_file {
    my ($self, $session_id) = @_;
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $session_id
    );
}

# Initialize session: load existing or create new
sub init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    my $session_id;

    if (exists $cookies{$self->{cookie_name}}) {
        $session_id = $cookies{$self->{cookie_name}}->value;
    }

    # Validate and attempt to load existing session
    if ($self->_validate_session_id($session_id)) {
        my $loaded = $self->_load_session($session_id);
        if ($loaded) {
            $self->{session_id} = $session_id;
            $self->{is_new} = 0;

            # Check if session has expired
            if ($self->_is_expired()) {
                $self->destroy();
                return $self->_create_new_session();
            }

            # Update last access time
            $self->{data}{_last_access} = time();
            $self->save();
            return 1;
        }
    }

    # No valid session found; create a new one
    return $self->_create_new_session();
}

# Create a brand new session
sub _create_new_session {
    my ($self) = @_;

    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created     => time(),
        _last_access => time(),
    };
    $self->{is_new} = 1;

    $self->save();
    return 1;
}

# Load session data from file using Storable::lock_retrieve
sub _load_session {
    my ($self, $session_id) = @_;

    my $file = $self->_session_file($session_id);

    unless (-e $file && -r $file) {
        return 0;
    }

    eval {
        $self->{data} = lock_retrieve($file);
    };
    if ($@) {
        warn "Failed to retrieve session file '$file': $@";
        return 0;
    }

    return 1;
}

# Check if the session has expired
sub _is_expired {
    my ($self) = @_;
    my $last_access = $self->{data}{_last_access} || 0;
    return (time() - $last_access > $self->{session_timeout}) ? 1 : 0;
}

# Save session data to file using Storable::lock_nstore
sub save {
    my ($self) = @_;

    my $file = $self->_session_file($self->{session_id});

    eval {
        lock_nstore($self->{data}, $file);
    };
    if ($@) {
        warn "Failed to store session file '$file': $@";
        return 0;
    }

    # Set file permissions to owner-only
    chmod 0600, $file;

    return 1;
}

# Get a session value
sub get {
    my ($self, $key) = @_;
    return $self->{data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    $self->{data}{$key} = $value;
    $self->save();
    return 1;
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;
    delete $self->{data}{$key};
    $self->save();
    return 1;
}

# Get all session data (excluding internal keys)
sub get_all {
    my ($self) = @_;
    my %public_data;
    for my $key (keys %{$self->{data}}) {
        next if $key =~ /^_/;
        $public_data{$key} = $self->{data}{$key};
    }
    return \%public_data;
}

# Destroy the session (delete file and clear data)
sub destroy {
    my ($self) = @_;

    my $file = $self->_session_file($self->{session_id});
    if (-e $file) {
        unlink $file or warn "Could not delete session file '$file': $!";
    }

    $self->{data} = {};
    $self->{session_id} = undef;
    $self->{is_new} = 0;

    return 1;
}

# Generate the session cookie for HTTP headers
sub cookie {
    my ($self, %opts) = @_;

    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id} || '',
        -expires  => $opts{expires}  || '+1h',
        -path     => $opts{path}     || '/',
        -secure   => $opts{secure}   // 0,
        -httponly  => $opts{httponly} // 1,
        -samesite => $opts{samesite} || 'Strict',
    );

    return $cookie;
}

# Get the current session ID
sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a newly created session
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Clean up expired sessions from the session directory
sub cleanup_expired {
    my ($self) = @_;

    my $dir = $self->{session_dir};
    my $prefix = $self->{session_prefix};
    my $count = 0;

    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory '$dir': $!";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E([a-f0-9]{64})$/;
        my $file = File::Spec->catfile($dir, $entry);

        eval {
            my $data = lock_retrieve($file);
            if ($data && ref $data eq 'HASH') {
                my $last_access = $data->{_last_access} || 0;
                if (time() - $last_access > $self->{session_timeout}) {
                    unlink $file;
                    $count++;
                }
            }
        };
        if ($@) {
            # Corrupted session file; remove it
            unlink $file;
            $count++;
        }
    }

    closedir($dh);
    return $count;
}

